import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { FaCamera, FaCheckCircle, FaLeaf, FaBrain } from 'react-icons/fa';
import { auth, provider } from './firebase/firebaseConfig';
import { 
  signInWithPopup, 
  createUserWithEmailAndPassword, 
  signInWithEmailAndPassword 
} from 'firebase/auth';

// Componente de Login/Registro
const Login = ({ onLogin }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isRegister, setIsRegister] = useState(false);
  const [error, setError] = useState('');

  const handleGoogleLogin = async () => {
    try {
      const result = await signInWithPopup(auth, provider);
      const user = result.user;
      localStorage.setItem("user", JSON.stringify(user));
      onLogin(user);
    } catch (err) {
      setError(err.message);
    }
  };

  const handleEmailAuth = async () => {
    try {
      let userCredential;
      if (isRegister) {
        userCredential = await createUserWithEmailAndPassword(auth, email, password);
      } else {
        userCredential = await signInWithEmailAndPassword(auth, email, password);
      }
      const user = userCredential.user;
      localStorage.setItem("user", JSON.stringify(user));
      onLogin(user);
    } catch (err) {
      setError(err.message);
    }
  };

  return (
    <div className="text-center mt-20 max-w-md mx-auto bg-white p-8 rounded shadow">
      <h1 className="text-3xl font-bold mb-4 text-green-700">PlantGuard</h1>

      {error && <p className="text-red-500 mb-2">{error}</p>}

      <input 
        type="email" 
        placeholder="Correo electrónico" 
        value={email} 
        onChange={(e) => setEmail(e.target.value)}
        className="w-full p-2 mb-2 border rounded"
      />
      <input 
        type="password" 
        placeholder="Contraseña" 
        value={password} 
        onChange={(e) => setPassword(e.target.value)}
        className="w-full p-2 mb-2 border rounded"
      />

      <button 
        onClick={handleEmailAuth}
        className="w-full bg-green-600 text-white py-2 rounded mb-2 hover:bg-green-700"
      >
        {isRegister ? "Registrarse" : "Iniciar sesión"}
      </button>

      <p className="text-sm mb-4">
        {isRegister ? "¿Ya tienes cuenta?" : "¿No tienes cuenta?"}{" "}
        <button 
          className="text-blue-600 underline" 
          onClick={() => setIsRegister(!isRegister)}
        >
          {isRegister ? "Inicia sesión" : "Regístrate"}
        </button>
      </p>

      <hr className="mb-4" />

      <button 
        onClick={handleGoogleLogin} 
        className="w-full bg-red-500 text-white py-2 rounded hover:bg-red-600"
      >
        Iniciar sesión con Google
      </button>
    </div>
  );
};

// Componente Dashboard (igual que antes)
const Dashboard = ({ user }) => {
  const [file, setFile] = useState(null);
  const [result, setResult] = useState(null);
  const [isLoading, setIsLoading] = useState(false);
  const [imagePreview, setImagePreview] = useState(null);

  const handleChange = (e) => {
    const selectedFile = e.target.files[0];
    setFile(selectedFile);

    if (selectedFile) {
      const reader = new FileReader();
      reader.onloadend = () => setImagePreview(reader.result);
      reader.readAsDataURL(selectedFile);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!file) return;

    const formData = new FormData();
    formData.append('file', file);
    setIsLoading(true);
    setResult(null);

    try {
      const res = await axios.post('http://localhost:5000/predict', formData);
      const { class_name, confidence } = res.data;

      setResult({
        disease: class_name.replaceAll('_', ' '),
        confidence: Math.round(confidence * 100)
      });
    } catch (err) {
      console.error(err);
      setResult({ error: 'Error al hacer la predicción.' });
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem("user");
    window.location.reload();
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-green-500 to-green-700 py-8 px-4">
      <div className="max-w-md mx-auto">
        {/* Header */}
        <div className="flex justify-between items-center mb-8">
          <div className="flex items-center">
            <div className="w-16 h-16 bg-white/20 rounded-2xl flex items-center justify-center shadow-lg mr-4 backdrop-blur-sm">
              <FaLeaf className="text-3xl text-white" />
            </div>
            <div>
              <h1 className="text-4xl font-bold text-white">PlantGuard</h1>
              <p className="text-white/90 text-lg">{user.displayName || user.email}</p>
            </div>
          </div>
          <button 
            onClick={handleLogout} 
            className="bg-red-500 text-white px-4 py-2 rounded hover:bg-red-600"
          >
            Cerrar sesión
          </button>
        </div>

        {/* Upload Section */}
        <div className="bg-white/10 backdrop-blur-md rounded-2xl p-6 mb-6 border border-white/20">
          <h2 className="text-xl font-bold text-white mb-4 text-center">Analiza tu Planta</h2>

          <form onSubmit={handleSubmit} className="space-y-4">
            <div className="relative">
              <input
                type="file"
                onChange={handleChange}
                accept="image/*"
                className="hidden"
                id="file-input"
              />
              <label
                htmlFor="file-input"
                className="block w-full h-64 bg-black/20 rounded-2xl flex items-center justify-center border-2 border-dashed border-white/30 cursor-pointer hover:border-white/50 transition-colors"
              >
                {imagePreview ? (
                  <img
                    src={imagePreview}
                    alt="Preview"
                    className="w-full h-full object-cover rounded-2xl"
                  />
                ) : (
                  <div className="text-center text-white/80">
                    <FaCamera className="text-4xl mb-3 mx-auto" />
                    <p className="text-sm">Haz clic para seleccionar una imagen</p>
                  </div>
                )}
              </label>
            </div>

            <button
              type="submit"
              disabled={!file || isLoading}
              className={`w-full py-3 px-6 rounded-lg font-semibold text-white transition-all duration-200 ${
                !file || isLoading
                  ? 'bg-gray-400 cursor-not-allowed'
                  : 'bg-green-600 hover:bg-green-700 hover:scale-105'
              }`}
            >
              {isLoading ? (
                <div className="flex items-center justify-center">
                  <FaBrain className="animate-pulse mr-2" />
                  Analizando...
                </div>
              ) : (
                'Iniciar Diagnóstico'
              )}
            </button>
          </form>
        </div>

        {/* Results Section */}
        {result && (
          <div className="bg-white rounded-2xl shadow-xl p-6 mb-6">
            <h2 className="text-xl font-bold text-gray-800 mb-4 text-center">Resultados</h2>

            {result.error ? (
              <div className="text-center text-red-600">
                <p className="text-lg">{result.error}</p>
              </div>
            ) : (
              <div className="text-center">
                <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-4">
                  <FaCheckCircle className="text-3xl text-green-600" />
                </div>
                <h3 className="text-2xl font-bold text-gray-800 mb-2">
                  {result.disease}
                </h3>
                <p className="text-lg text-gray-600">
                  Confianza: {result.confidence}%
                </p>

                <div className="mt-4 bg-gray-50 rounded-lg p-4">
                  <h4 className="font-semibold text-gray-800 mb-2">Recomendaciones:</h4>
                  <p className="text-sm text-gray-600">
                    Consulta con un especialista para tratamiento específico.
                  </p>
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

// App principal
function App() {
  const [user, setUser] = useState(null);

  useEffect(() => {
    const storedUser = localStorage.getItem("user");
    if (storedUser) setUser(JSON.parse(storedUser));
  }, []);

  return <div>{user ? <Dashboard user={user} /> : <Login onLogin={setUser} />}</div>;
}

export default App;
